import { useState, useEffect, useCallback } from 'react';
import { getAllPrices, getCoinHistory, findOrCreateCoin } from '../services/cryptoService';
import { calculateIndicators, generateSignal } from '../utils/helpers';
import { COINS } from '../utils/constants';

export function useCrypto() {
  const [selectedCoin, setSelectedCoin] = useState(COINS[0]);
  const [prices, setPrices]             = useState({});
  const [chartData, setChartData]       = useState(null);
  const [indicators, setIndicators]     = useState(null);
  const [signal, setSignal]             = useState(null);
  const [selectedBot, setSelectedBot]   = useState('trend');
  const [timeframe, setTimeframe]       = useState('1h');
  const [signalHistory, setSignalHistory] = useState([]);
  const [isLoading, setIsLoading]       = useState(false);

  useEffect(() => {
    setPrices(getAllPrices());
    const id = setInterval(() => setPrices(getAllPrices()), 3000);
    return () => clearInterval(id);
  }, []);

  const analyzeCoin = useCallback((coin, tf, botId) => {
    setIsLoading(true);
    setTimeout(() => {
      const history = getCoinHistory(coin.sym, tf);
      const inds    = calculateIndicators(history.prices);
      const sig     = generateSignal(inds, botId);
      setChartData(history);
      setIndicators(inds);
      setSignal(sig);
      setIsLoading(false);
      if (sig.type !== 'BEKLE') {
        const isWin = Math.random() < 0.72;
        const pct = isWin
          ? '+' + (Math.random() * 4 + 0.5).toFixed(2) + '%'
          : '-' + (Math.random() * 2 + 0.2).toFixed(2) + '%';
        setSignalHistory(prev => [
          { id: Date.now(), sym: coin.sym, type: sig.type, result: pct, win: isWin },
          ...prev.slice(0, 9),
        ]);
      }
    }, 600);
  }, []);

  const selectCoin = useCallback((sym) => {
    const coin = COINS.find(c => c.sym === sym) || COINS[0];
    setSelectedCoin(coin);
    analyzeCoin(coin, timeframe, selectedBot);
  }, [timeframe, selectedBot, analyzeCoin]);

  const searchCoin = useCallback((query) => {
    const coin = findOrCreateCoin(query);
    setSelectedCoin(coin);
    analyzeCoin(coin, timeframe, selectedBot);
  }, [timeframe, selectedBot, analyzeCoin]);

  const changeBot = useCallback((botId) => {
    setSelectedBot(botId);
    analyzeCoin(selectedCoin, timeframe, botId);
  }, [selectedCoin, timeframe, analyzeCoin]);

  const changeTimeframe = useCallback((tf) => {
    setTimeframe(tf);
    analyzeCoin(selectedCoin, tf, selectedBot);
  }, [selectedCoin, selectedBot, analyzeCoin]);

  useEffect(() => {
    analyzeCoin(COINS[0], '1h', 'trend');
  }, []); // eslint-disable-line

  return {
    selectedCoin, prices, chartData, indicators, signal,
    selectedBot, timeframe, signalHistory, isLoading,
    selectCoin, searchCoin, changeBot, changeTimeframe,
  };
}
